+package ratelimiter
+
+import (
+	"sync"
+	"time"
+)
+
+// realClock implements Clock using the actual system time.
+type realClock struct{}
+
+func (realClock) Now() time.Time { return time.Now() }
+
+// bucket holds the token state for a single key.
+type bucket struct {
+	tokens int       // current token count
+	last   time.Time // last time tokens were refilled
+}
+
+// tokenLimiter implements the Limiter interface using a token‑bucket algorithm.
+type tokenLimiter struct {
+	cfg     Config
+	clock   Clock
+	burst   int                 // effective burst size (Rate if Burst==0)
+	mu      sync.Mutex          // protects buckets map
+	buckets map[string]*bucket // per‑key state
+}
+
+// newLimiter returns a Limiter implementation.
+func newLimiter(cfg Config, clock Clock) Limiter {
+	if clock == nil {
+		clock = realClock{}
+	}
+	burst := cfg.Burst
+	if burst == 0 {
+		burst = cfg.Rate
+	}
+	return &tokenLimiter{
+		cfg:     cfg,
+		clock:   clock,
+		burst:   burst,
+		buckets: make(map[string]*bucket),
+	}
+}
+
+// refill calculates how many tokens to add based on elapsed time.
+func (l *tokenLimiter) refill(b *bucket, now time.Time) {
+	if now.After(b.last) {
+		elapsed := now.Sub(b.last)
+		// Tokens to add = elapsed * Rate / Window, using integer arithmetic.
+		add := int(elapsed.Nanoseconds() *
+			int64(l.cfg.Rate) / int64(l.cfg.Window.Nanoseconds()))
+		if add > 0 {
+			b.tokens += add
+			if b.tokens > l.burst {
+				b.tokens = l.burst
+			}
+			b.last = now
+		}
+	}
+}
+
+// Allow returns true if a request for key should be permitted.
+func (l *tokenLimiter) Allow(key string) bool {
+	l.mu.Lock()
+	defer l.mu.Unlock()
+
+	b, ok := l.buckets[key]
+	if !ok {
+		// First request for this key gets a full burst.
+		b = &bucket{tokens: l.burst, last: l.clock.Now()}
+		l.buckets[key] = b
+	}
+
+	now := l.clock.Now()
+	l.refill(b, now)
+
+	if b.tokens > 0 {
+		b.tokens--
+		return true
+	}
+	return false
+}
+
+// Reset clears the rate‑limiting state for the given key.
+func (l *tokenLimiter) Reset(key string) {
+	l.mu.Lock()
+	delete(l.buckets, key)
+	l.mu.Unlock()
+}
